function getOperationMapRows({ includeInactive = true } = {}) {
  return [...(directoryState?.operationMap || [])]
    .filter((item) => item && item.id)
    .filter((item) => includeInactive || item.status !== "Отключен")
    .sort((left, right) => String(left.name || "").localeCompare(String(right.name || ""), "ru"));
}

function getOperationMapItem(operationId) {
  const item = getOperationMapRows().find((row) => row.id === operationId) || null;
  if (item?.legacyAliasOf && item.legacyAliasOf !== item.id) {
    return getOperationMapRows().find((row) => row.id === item.legacyAliasOf) || item;
  }
  return item;
}

function findOperationMapItemByNameAndWorkCenter(operationName = "", workCenterId = "") {
  const normalizedName = normalizeLookupText(operationName);
  const routeWorkCenterId = getRouteInstructionWorkCenterId(workCenterId);
  if (!normalizedName) return null;
  const rows = getOperationMapRows();
  const exact = rows.find((operation) => (
    normalizeLookupText(operation.name) === normalizedName
    && (!routeWorkCenterId || getOperationRouteWorkCenterId(operation) === routeWorkCenterId)
  ));
  if (exact) return exact;
  const nameMatches = rows.filter((operation) => normalizeLookupText(operation.name) === normalizedName);
  return nameMatches.length === 1 ? nameMatches[0] : null;
}

function getLegacyOperationWorkCenterId(source = {}) {
  const explicitWorkCenterId = String(source.workCenterId || "").trim();
  if (explicitWorkCenterId && getWorkCenter(explicitWorkCenterId)) return explicitWorkCenterId;
  return resolveWorkCenterIdFromName(source.departmentName || source.department || source.workCenter || "")
    || resolveWorkCenterIdFromName(source.operationName || source.name || "")
    || getRouteInstructionWorkCenters({ includeWarehouse: false })[0]?.id
    || "D5";
}

function ensureOperationMapItemFromLegacyOperation(source = {}, stamp = new Date().toISOString()) {
  const existingById = source.operationId ? getOperationMapItem(source.operationId) : null;
  if (existingById) return existingById;
  const mesReplacement = findMesOperationReplacement(source);
  if (mesReplacement) return getOperationMapItem(mesReplacement.id) || normalizeDirectoryRow("operations", mesReplacement);

  const operationName = String(source.name || source.operationName || "").trim();
  if (!operationName) return null;

  const workCenterId = getLegacyOperationWorkCenterId(source);
  const existingByName = findOperationMapItemByNameAndWorkCenter(operationName, workCenterId);
  if (existingByName) return existingByName;

  return null;
}

function applyOperationMapItemToRouteStep(step = {}, operation = {}, stamp = new Date().toISOString()) {
  const workCenterId = getOperationRouteWorkCenterId(operation) || step.workCenterId || getRouteInstructionWorkCenters({ includeWarehouse: false })[0]?.id || "D5";
  const planningCandidates = getPlanningCandidateWorkCenterIdsForRouteWorkCenter(workCenterId, operation, planningState);
  const singlePlanningWorkCenterId = planningCandidates.length === 1 ? planningCandidates[0] : "";
  const explicitPlanningWorkCenterId = mapLegacyWorkCenterId(step.planningWorkCenterId || "");
  const selectedPlanningWorkCenterId = explicitPlanningWorkCenterId && planningCandidates.includes(explicitPlanningWorkCenterId)
    ? explicitPlanningWorkCenterId
    : singlePlanningWorkCenterId;
  const resourceId = selectedPlanningWorkCenterId
    ? getPlanningResourceForRouteStep({ ...step, workCenterId }, selectedPlanningWorkCenterId, step.resourceId)
    : "";
  const resource = resourceId ? getProductionResource(resourceId) : null;
  const calculationType = step.calculationType || getDefaultOperationCalculationType(workCenterId, operation);
  return normalizeRouteStepCalculationFields({
    ...step,
    operationId: operation.id || "",
    operationName: operation.name || "",
    workCenterId,
    planningWorkCenterId: selectedPlanningWorkCenterId && planningCandidates.length > 1 ? selectedPlanningWorkCenterId : "",
    workCenterOverride: false,
    unitsPerHour: operation.unitsPerHour || step.unitsPerHour || getWorkCenterUnitsPerHour(workCenterId),
    resourceId,
    calculationType,
    secondsPerPanel: calculationType === "manual" || calculationType === "normative"
      ? Number(step.secondsPerPanel || getDefaultSecondsPerPanel(workCenterId, step.boardsPerPanel || 1))
      : Number(step.secondsPerPanel || 0),
    setupMin: Math.max(0, Number(step.setupMin ?? resource?.changeoverMin ?? 0)),
    requiresBatch: operation.requiresBatch,
    isWarehouseOperation: operation.isWarehouse,
    updatedAt: stamp,
  }, planningState);
}

function getDefaultOperationNameForWorkCenter(center = {}) {
  const normalizedName = normalizeLookupText(center.name || "");
  const normalizedCode = normalizeLookupText(center.code || "");

  if (center.id === "warehouse" || center.unitType === "warehouse" || normalizedName.includes("склад")) {
    return "Поступление из производства";
  }
  if (normalizedName.includes("smt") || normalizedCode.includes("smt")) return "SMT-монтаж компонентов";
  if (normalizedName.includes("aoi") || normalizedCode.includes("aoi")) return "AOI-контроль";
  if (normalizedName.includes("отмыв")) return "Отмывка плат";
  if (normalizedName.includes("ручн")) return "Ручной монтаж компонентов";
  if (normalizedName.includes("тест") || normalizedName.includes("испыт")) return "Функциональное тестирование";
  if (normalizedName.includes("лакир")) return "Лакировка";
  if (normalizedName.includes("слесар") || normalizedName.includes("механ")) return "Слесарная подготовка";
  if (normalizedName.includes("сбор")) return "Финальная сборка";
  if (normalizedName.includes("отк") || normalizedName.includes("контрол")) return "Контроль качества";
  if (normalizedName.includes("планир")) return "Планирование производства";
  if (normalizedName.includes("программ")) return "Программирование";
  if (normalizedName.includes("закуп") || normalizedName.includes("снабжен")) return "Закупка материалов";

  return `Работа отдела ${center.name || center.code || "без названия"}`;
}

function makeDefaultOperationCode(center = {}) {
  const source = String(center.code || center.id || "OP")
    .toUpperCase()
    .replace(/[^A-ZА-Я0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 18);
  return `OP-${source || "UNIT"}`;
}

function ensureWorkCenterOperations() {
  const nextOperationMap = mergeMesOperationMap(directoryState.operationMap);
  if (JSON.stringify(nextOperationMap) !== JSON.stringify(directoryState.operationMap || [])) {
    directoryState.operationMap = nextOperationMap;
    directoryState = normalizeDirectoryState(directoryState, { mergeFallback: false });
    persistDirectoryState();
  }

  localStorage.setItem(WORK_CENTER_OPERATIONS_SEEDED_STORAGE_KEY, "1");
}

function migrateLegacyOperationsToDirectory() {
  const stamp = new Date().toISOString();
  const initialOperationCount = (directoryState.operationMap || []).length;
  let planningChanged = false;
  let directoryChanged = false;

  planningState.routeSteps = (planningState.routeSteps || []).map((step) => {
    const operation = getOperationMapItem(step.operationId)
      || ensureOperationMapItemFromLegacyOperation(step, stamp);
    if (!operation) return step;
    const nextStep = applyOperationMapItemToRouteStep(step, operation, stamp);
    const changed = [
      "operationId",
      "operationName",
      "workCenterId",
      "unitsPerHour",
      "resourceId",
      "calculationType",
      "secondsPerPanel",
      "setupMin",
      "requiresBatch",
      "isWarehouseOperation",
    ].some((key) => String(step[key] ?? "") !== String(nextStep[key] ?? ""));
    if (changed) planningChanged = true;
    return changed ? nextStep : step;
  });

  const routeStepById = new Map((planningState.routeSteps || []).map((step) => [step.id, step]));
  planningState.slots = (planningState.slots || []).map((slot) => {
    const step = routeStepById.get(slot.routeStepId);
    if (!step || !step.operationId) return slot;
    const nextSlot = recalculateSlotEndByQuantity({
      ...slot,
      operationId: step.operationId || slot.operationId || "",
      operationName: step.operationName || slot.operationName,
      workCenterId: step.workCenterId || slot.workCenterId,
      unitsPerHour: step.unitsPerHour || slot.unitsPerHour,
      resourceId: step.resourceId || slot.resourceId || "",
      calculationType: step.calculationType || slot.calculationType || "",
      secondsPerPanel: step.secondsPerPanel || slot.secondsPerPanel || 0,
      setupMin: step.setupMin || slot.setupMin || 0,
      bomListId: step.bomListId || slot.bomListId || "",
      updatedAt: stamp,
    }, planningState);
    const changed = ["operationId", "operationName", "workCenterId", "unitsPerHour", "resourceId", "calculationType", "secondsPerPanel", "setupMin", "bomListId"]
      .some((key) => String(slot[key] ?? "") !== String(nextSlot[key] ?? ""));
    if (changed) planningChanged = true;
    return changed ? nextSlot : slot;
  });

  directoryState.specifications = (directoryState.specifications || []).map((specification) => {
    if (!Array.isArray(specification.structureItems) || !specification.structureItems.length) return specification;
    let specificationChanged = false;
    const structureItems = specification.structureItems.map((item) => {
      if (!isSchedulableFulfillmentMode(item.fulfillmentMode || item.executionType || "")) return item;
      const operation = getOperationMapItem(item.operationId)
        || ensureOperationMapItemFromLegacyOperation({
          operationName: item.operationName,
          departmentName: item.departmentName,
        }, stamp);
      if (!operation) return item;
      const center = getWorkCenter(operation.workCenterId);
      const nextItem = {
        ...item,
        operationId: operation.id,
        operationName: operation.name || "",
        departmentName: center?.name || item.departmentName || "",
      };
      const changed = ["operationId", "operationName", "departmentName"]
        .some((key) => String(item[key] ?? "") !== String(nextItem[key] ?? ""));
      if (changed) specificationChanged = true;
      return changed ? nextItem : item;
    });
    if (!specificationChanged) return specification;
    directoryChanged = true;
    return { ...specification, structureItems, updatedAt: stamp };
  });

  directoryChanged = directoryChanged || initialOperationCount !== (directoryState.operationMap || []).length;

  if (directoryChanged) {
    directoryState = normalizeDirectoryState(directoryState, { mergeFallback: false });
    persistDirectoryState();
  }
  if (planningChanged) {
    planningState = normalizePlanningState(planningState);
    persistState();
  }
}

function renderPlanningPage() {
  const routes = getRoutesForModule();
  const activeRoute = getActiveRouteForModule();
  const activeProject = getProject(activeRoute?.specificationId || activeRoute?.projectId);
  const activeSpecification = getRouteSpecification(activeRoute);
  const activeBom = getRouteBomList(activeRoute);
  const stats = getRouteModuleStats(activeRoute);
  const transferSummary = getPlanningRouteTransferSummary(activeRoute);
  const routeTitle = activeRoute?.name || "Заказ-наряд не выбран";
  const specificationTitle = activeRoute
    ? activeBom?.name || activeSpecification?.name || getProjectDisplayName(activeProject) || "BOM или состав изделия не выбран"
    : "выберите карту слева";

  if (!routes.length) {
    return `
      <section class="planning-empty-page" data-layout="main-content" aria-label="${WORK_ORDERS_MODULE_LABEL}">
        <section class="planning-empty-panel">
          <div class="planning-empty-icon">${icon("calendar")}</div>
          <div>
            <span class="eyebrow">Новый модуль</span>
            <h2>${WORK_ORDERS_MODULE_LABEL}</h2>
            <p>Заказ-нарядов пока нет. Создайте маршрутную карту в модуле «Маршрутная карта», затем создайте по ней заказ-наряд.</p>
          </div>
        </section>
      </section>
    `;
  }

  return `
    <section class="planning-page module-data-page" data-layout="main-content" aria-label="${WORK_ORDERS_MODULE_LABEL}">
      <aside class="directory-sidebar module-data-sidebar planning-sidebar">
        <div class="directory-sidebar-head">
          <span class="eyebrow">Очередь</span>
          <h1>${WORK_ORDERS_MODULE_LABEL}</h1>
        </div>
        <div class="module-entity-list">
          <div class="module-list-label">Заказ-наряды</div>
          ${routes.map((route) => {
            const routeProject = getRouteProductionContext(route);
            const routeSpecification = getRouteSpecification(route);
            const routeBom = getRouteBomList(route);
            const steps = getRouteStepsForModule(route.id);
            const routeSummary = getPlanningRouteTransferSummary(route);
            const routeOrderState = getPlanningRouteOrderState(route, routeSummary);
            return `
              <button class="module-entity-item ${route.id === activeRoute?.id ? "is-active" : ""}" data-planning-route-open="${escapeAttribute(route.id)}" type="button">
                <span>
                  <strong>${escapeHtml(route.name || "Заказ-наряд")}</strong>
                  <small>${escapeHtml(routeBom?.name || routeSpecification?.name || getProjectDisplayName(routeProject) || "BOM или состав изделия не найден")} · ${steps.length} операций · ${escapeHtml(routeOrderState.label)}</small>
                </span>
                <em class="${escapeAttribute(routeOrderState.tone)}">${routeSummary.planned || steps.length}</em>
              </button>
            `;
          }).join("")}
        </div>
      </aside>

      <div class="directory-workspace module-data-workspace" data-layout="page-workspace">
        <header class="directory-header">
          <div>
            <span class="eyebrow">Заказ-наряд</span>
            <h2>${escapeHtml(routeTitle)}</h2>
            <p>${escapeHtml(activeRoute ? `${specificationTitle}: заказ-наряд создан на основе маршрутной карты для подготовки к Ганту.` : "Выберите заказ-наряд в перечне, чтобы настроить количество, обеспечение и передачу в Гант.")}</p>
          </div>
          <div class="directory-actions">
            <button class="secondary-button danger" data-planning-route-cancel="${escapeAttribute(activeRoute?.id || "")}" type="button" ${activeRoute && transferSummary.planned ? "" : "disabled"}>
              ${icon("close")}<span>Отменить заказ</span>
            </button>
            <button class="primary-button" data-planning-route-to-gantt="${escapeAttribute(activeRoute?.id || "")}" type="button" ${activeRoute && transferSummary.steps.length ? "" : "disabled"}>
              ${icon("gantt")}<span>Передать в Гант</span>
            </button>
          </div>
        </header>

        <div class="module-data-content planning-route-content">
          ${activeRoute ? `
          ${renderPlanningWorkbench(activeRoute, transferSummary, stats.steps)}
          ` : `
          <section class="module-panel planning-route-card">
            <div class="report-card-head">
              <strong>Заказ-наряд</strong>
              <span>не выбран</span>
            </div>
            ${renderModulePreviewEmpty({
              iconName: "calendar",
              title: "Заказ-наряд не выбран",
              text: "Выберите заказ-наряд слева или создайте его из модуля «Маршрутная карта», чтобы подготовить план к Ганту.",
            })}
          </section>
          `}
        </div>
      </div>
    </section>
  `;
}

function renderPlanningWorkbenchV2Page() {
  const routes = getRoutesForModule();
  const activeRoute = getActiveRouteForModule();
  const stats = getRouteModuleStats(activeRoute);
  const transferSummary = getPlanningRouteTransferSummary(activeRoute);
  const routeSteps = stats.steps || getRouteStepsForModule(activeRoute?.id || "");
  const tasks = getPlanningTasksForRoute(activeRoute, routeSteps);
  const selectedItem = activeRoute ? getPlanningActiveWorkItem(activeRoute, tasks, routeSteps) : "";
  const workOrderView = getWorkOrderViewModel(activeRoute, { summary: transferSummary, routeSteps });
  const orderTitle = activeRoute ? workOrderView.title : "Заказ-наряд не выбран";
  const orderSubtitle = activeRoute ? workOrderView.subtitle : "";
  const planningTransition = workOrderView.transitionToPlanning || getMesFlowTransitionView("workOrderToGanttSlot");

  if (!routes.length) {
    return `
      <section class="planning-empty-page planning-v2-empty" data-layout="main-content" aria-label="${WORK_ORDERS_MODULE_LABEL}">
        <section class="planning-empty-panel">
          <div class="planning-empty-icon">${icon("calendar")}</div>
          <div>
            <h2>${WORK_ORDERS_MODULE_LABEL}</h2>
            <p>Нет маршрутных заданий для сборки заказ-наряда.</p>
          </div>
        </section>
      </section>
    `;
  }

  return `
    <section class="planning-page module-data-page planning-v2-page is-heroui is-flat-workbench is-route-structure" data-layout="main-content" aria-label="${WORK_ORDERS_MODULE_LABEL}">
      ${renderPlanningWorkbenchV2Queue(routes, activeRoute)}

      <div class="planning-v2-main" data-layout="page-workspace">
        <header class="planning-v2-header">
          <div>
            <span class="eyebrow">Производственный документ</span>
            <h2>${escapeHtml(orderTitle)}</h2>
            ${orderSubtitle ? `<p>${escapeHtml(orderSubtitle)}</p>` : ""}
          </div>
          <div class="directory-actions planning-v2-actions">
            <button class="secondary-button danger" data-planning-route-cancel="${escapeAttribute(activeRoute?.id || "")}" type="button" ${activeRoute && transferSummary.planned ? "" : "disabled"}>
              ${icon("close")}<span>Отменить заказ</span>
            </button>
            <button class="primary-button" data-planning-route-to-gantt="${escapeAttribute(activeRoute?.id || "")}" type="button" ${activeRoute && transferSummary.steps.length ? "" : "disabled"} title="${escapeAttribute(planningTransition.description || "")}">
              ${icon("gantt")}<span>${escapeHtml(planningTransition.actionLabel || "Передать в планирование")}</span>
            </button>
          </div>
        </header>

        ${activeRoute ? `
          <div class="planning-v2-workspace">
            ${renderPlanningWorkbenchV2RouteMap(activeRoute, transferSummary, tasks, routeSteps, selectedItem)}
            <div class="planning-v2-detail planning-work-detail" aria-label="Рабочая область выбранного этапа">
              ${renderPlanningWorkbenchV2Detail(activeRoute, transferSummary, tasks, routeSteps, selectedItem)}
            </div>
          </div>
        ` : `
          <section class="module-panel planning-v2-route-map">
            ${renderModulePreviewEmpty({
              iconName: "calendar",
              title: "Заказ-наряд не выбран",
              text: "Выберите заказ-наряд слева.",
            })}
          </section>
        `}
      </div>
    </section>
  `;
}

function renderPlanningWorkbenchV2Queue(routes, activeRoute) {
  return `
    <aside class="directory-sidebar module-data-sidebar planning-v2-queue" data-layout="sidebar" data-visual-qa-target="planning-work-order-sidebar" aria-label="Список заказ-нарядов">
      <div class="directory-sidebar-head">
        <span class="eyebrow">Планирование</span>
        <h1>Заказ-наряды</h1>
      </div>
      <div class="module-entity-list planning-v2-route-list">
        ${routes.map((route) => {
          const workOrderView = getWorkOrderViewModel(route);
          const state = workOrderView.status;
          const quantity = workOrderView.quantity || getPlanningRouteQuantity(route);
          return `
            <button class="module-entity-item planning-v2-route-item ${route.id === activeRoute?.id ? "is-active" : ""}" data-planning-route-open="${escapeAttribute(route.id)}" type="button">
              <span>
                <strong>${escapeHtml(workOrderView.queueTitle)}</strong>
                <small>${escapeHtml(getRouteDocumentKindShortLabel(route))} · ${quantity.toLocaleString("ru-RU")} шт.</small>
              </span>
              <em class="is-${escapeAttribute(state.tone)}">${escapeHtml(state.label)}</em>
            </button>
          `;
        }).join("")}
      </div>
    </aside>
  `;
}

function renderPlanningWorkbenchV2RouteMap(route, transferSummary, tasks, routeSteps, selectedItem) {
  const planningQuantity = normalizeQuantity(transferSummary?.planningQuantity || getPlanningRouteQuantity(route));
  const supplySummary = getPlanningSupplySummary(route, transferSummary, routeSteps);
  const chain = buildPlanningProductionChain(route, transferSummary, tasks, routeSteps);
  const scheduleExpected = Number(transferSummary?.expected || 0);
  const schedulePlanned = Number(transferSummary?.planned || 0);
  const scheduleMissing = Math.max(0, scheduleExpected - schedulePlanned);
  const scheduleTone = scheduleExpected && !scheduleMissing ? "ok" : scheduleExpected ? "warning" : "neutral";
  const scheduleStatus = scheduleExpected && !scheduleMissing ? "готово" : scheduleMissing ? `${scheduleMissing} не размещено` : "подготовить";
  const shiftOrders = getPlanningShiftOrdersForRoute(route, routeSteps);

  return `
    <section class="module-panel planning-v2-route-map planning-order-structure-panel" aria-label="Структура заказ-наряда">
      <div class="planning-v2-map-head">
        <div>
          <strong>Структура заказ-наряда</strong>
          <span>${planningQuantity.toLocaleString("ru-RU")} шт. · ${tasks.length.toLocaleString("ru-RU")} объектов · ${routeSteps.length.toLocaleString("ru-RU")} операций</span>
        </div>
        <em class="planning-section-tag">${escapeHtml(getRouteDocumentKindLabel(route))}</em>
      </div>

      <div class="planning-order-checkpoints" aria-label="Контрольные разделы заказ-наряда">
          ${renderPlanningWorkbenchV2Phase({
            id: "supply",
            selectedItem,
            title: "Состав и обеспечение",
            meta: "",
            status: supplySummary.blocking ? `${supplySummary.blocking} проблем` : "готово",
            tone: supplySummary.blocking ? "warning" : "ok",
          })}

          ${renderPlanningWorkbenchV2Phase({
            id: "chain",
            selectedItem,
            title: "Правило запуска",
            meta: "",
            status: chain.issues.length ? `${chain.issues.length} проблем` : "готово",
            tone: chain.issues.length ? "warning" : "ok",
          })}

          ${renderPlanningWorkbenchV2Phase({
            id: "schedule",
            selectedItem,
            title: "Размещение в Ганте",
            meta: "",
            status: scheduleStatus,
            tone: scheduleTone,
          })}

          ${renderPlanningWorkbenchV2Phase({
            id: "shifts",
            selectedItem,
            title: "Сменные наряды",
            meta: "",
            status: shiftOrders.length ? `${shiftOrders.length} смен` : "после Ганта",
            tone: shiftOrders.length ? "ok" : "neutral",
          })}
      </div>

      ${renderPlanningOrderStructureTable(route, tasks, routeSteps, selectedItem, planningQuantity)}
    </section>
  `;
}

function getPlanningDemoLaborKey(route, itemId = "") {
  return `${route?.id || "route"}::${String(itemId || "").trim()}`;
}

function getPlanningDemoLaborValue(key = "") {
  return normalizePlanningDemoLaborByRow(ui.planningDemoLaborByRow)[key] || "";
}

function getPlanningDemoLaborPlaceholder(durationMs = 0) {
  return durationMs > 0 ? `расчет: ${formatDuration(durationMs)}` : "демо-оценка";
}

function getPlanningStepDemoLaborPlaceholder(route, step, planningQuantity) {
  const snapshot = getRouteStepLaborSnapshot(route, step, { routeQuantity: planningQuantity });
  return getPlanningDemoLaborPlaceholder(snapshot.durationMs);
}

function getPlanningTaskDemoLaborPlaceholder(route, steps = [], planningQuantity) {
  const durationMs = steps.reduce((sum, step) => (
    sum + Math.max(0, Number(getRouteStepLaborSnapshot(route, step, { routeQuantity: planningQuantity }).durationMs || 0))
  ), 0);
  return getPlanningDemoLaborPlaceholder(durationMs);
}

function renderPlanningDemoLaborField(key, placeholder) {
  const value = getPlanningDemoLaborValue(key);
  return `
    <label class="planning-demo-labor-field" title="Демо-функция: редактируется только как UI-пометка и не влияет на расчеты">
      <span>Демо</span>
      <input
        data-planning-demo-labor="${escapeAttribute(key)}"
        type="text"
        value="${escapeAttribute(value)}"
        placeholder="${escapeAttribute(placeholder)}"
        aria-label="Демо-функция: трудозатраты"
      />
    </label>
  `;
}

function renderPlanningOrderStructureTable(route, tasks, routeSteps, selectedItem, planningQuantity) {
  if (!tasks.length) {
    return `
      <div class="planning-muted-state">
        ${icon("info")}
        <span>Состав заказ-наряда не найден.</span>
      </div>
    `;
  }

  return `
    <div class="speki-structure-table-wrap route-object-table-wrap planning-order-table-wrap" data-layout="table">
      <table class="directory-table speki-structure-table route-object-table planning-order-table">
        <thead>
          <tr>
            <th>П/п</th>
            <th>Тип</th>
            <th>Объект / операция</th>
            <th>Кол-во</th>
            <th>Трудозатраты</th>
            <th>Состояние</th>
          </tr>
        </thead>
        <tbody>
          ${tasks.map((task) => renderPlanningOrderTaskRows(route, task, routeSteps, selectedItem, planningQuantity)).join("")}
        </tbody>
      </table>
    </div>
  `;
}

function renderPlanningOrderTaskRows(route, task, routeSteps, selectedItem, planningQuantity) {
  const stats = getPlanningTaskOperationStats(route, task, routeSteps);
  const readiness = getPlanningTaskReadiness(task, stats);
  const taskTypeVisual = getRouteTaskTypeVisual(task);
  const taskQuantity = normalizeQuantity(task.quantity || 1);
  const orderQuantity = normalizeQuantity(planningQuantity * taskQuantity);
  const taskUnit = /маршрут/i.test(task.unit || "") ? "шт." : task.unit || "шт.";
  const taskItemId = getPlanningWorkItemId("task", task.id);
  const taskDemoLaborKey = getPlanningDemoLaborKey(route, taskItemId);
  const taskDemoLaborPlaceholder = getPlanningTaskDemoLaborPlaceholder(route, stats.steps, planningQuantity);
  const taskDisplayNumber = task.number === "00" ? "1" : task.number || "1";
  const taskObjectContent = `
    <div class="route-object-name-cell planning-order-name-cell">
      <strong title="${escapeAttribute(task.title || "Составная часть")}">${escapeHtml(task.title || "Составная часть")}</strong>
      <small>${escapeHtml([task.parentTitle, getPlanningTaskBomLabel(task)].filter(Boolean).join(" · ") || getRouteTaskTypeLabel(task))}</small>
    </div>
  `;

  return `
    <tr
      class="route-object-row planning-order-object-row ${taskItemId === selectedItem ? "is-selected" : ""} ${task.isMain ? "is-route-main" : ""} ${task.isOrphan ? "is-route-orphan" : ""}"
      data-planning-order-row="${escapeAttribute(taskItemId)}"
      style="--speki-level: ${Number(task.level || 0)};"
    >
      <td><span class="speki-row-number">${escapeHtml(taskDisplayNumber)}</span></td>
      <td>${renderRouteTypeIconBadge(taskTypeVisual)}</td>
      <td>${renderRouteTreeCell({
        level: Number(task.level || 0),
        hasChildren: Boolean(task.hasChildren || stats.steps.length),
        isLast: task.isLast !== false,
        continuationLevels: task.continuationLevels || [],
        visual: taskTypeVisual,
        content: taskObjectContent,
        className: "is-route-object is-planning-order-object",
      })}</td>
      <td>
        <span class="speki-static-cell planning-order-quantity">
          <strong>${orderQuantity.toLocaleString("ru-RU")}</strong>
          <small>${escapeHtml(taskUnit)}</small>
        </span>
      </td>
      <td>${renderPlanningDemoLaborField(taskDemoLaborKey, taskDemoLaborPlaceholder)}</td>
      <td>
        <div class="planning-order-state-cell">
          <span class="planning-v2-state-token is-${escapeAttribute(readiness.tone)}">${escapeHtml(readiness.label)}</span>
          <button class="icon-button" data-planning-work-item="${escapeAttribute(taskItemId)}" type="button" title="Открыть объект">${icon("chevronRight")}</button>
        </div>
      </td>
    </tr>
    ${stats.steps.length ? stats.steps.map((step, index) => renderPlanningOrderStepRow(route, task, step, index, stats.steps, selectedItem, planningQuantity, {
      continuationLevels: getRouteTaskOperationContinuationLevels(task),
      isLast: index === stats.steps.length - 1,
    })).join("") : `
      <tr class="route-object-operation-row planning-order-operation-row is-empty" style="--speki-level: ${Number(task.level || 0) + 1};">
        <td colspan="6">
          <div class="route-task-empty">${icon("info")}<span>Для этого объекта операции не заданы</span></div>
        </td>
      </tr>
    `}
  `;
}

function renderPlanningOrderStepRow(route, task, step, index, taskSteps = [], selectedItem, planningQuantity, treeOptions = {}) {
  const itemId = getPlanningWorkItemId("step", step.id);
  const stepDemoLaborKey = getPlanningDemoLaborKey(route, itemId);
  const stepDemoLaborPlaceholder = getPlanningStepDemoLaborPlaceholder(route, step, planningQuantity);
  const tone = getPlanningStepTone(step);
  const stepTypeVisual = getRouteStepTypeVisual(step);
  const isSmtStep = routeStepRequiresManualPlanningLine(step, planningState) || isSmtOperationWorkCenter(step.workCenterId, step, planningState);
  const stepQuantity = getRouteStepQuantityForBatch(step, { quantity: planningQuantity });
  const stepMeta = [
    getPlanningStepLineLabel(step),
    isSmtStep ? "SMT" : isManufacturingOutputReceiptRouteStep(step) ? "приемка" : "",
  ].filter(Boolean).join(" · ");
  const level = Number.isFinite(Number(treeOptions.level))
    ? Number(treeOptions.level)
    : Number(task?.level || 0) + 1;
  const stepContent = `
    <div class="route-object-name-cell planning-order-name-cell planning-order-step-name">
      <strong title="${escapeAttribute(step.operationName || "Операция")}">${escapeHtml(step.operationName || "Операция")}</strong>
      <small>${escapeHtml(stepMeta || "ресурс не выбран")}</small>
    </div>
  `;

  return `
    <tr
      class="route-step-compact-row planning-order-step-row ${itemId === selectedItem ? "is-selected" : ""} ${isManufacturingOutputReceiptRouteStep(step) ? "is-warehouse" : ""} is-${escapeAttribute(tone)}"
      data-planning-order-row="${escapeAttribute(itemId)}"
      style="--speki-level: ${level};"
    >
      <td>
        <div class="route-step-compact-order">
          <span class="route-step-order-badge" title="Позиция операции в объекте маршрута">${index + 1}</span>
        </div>
      </td>
      <td>${renderRouteTypeIconBadge(stepTypeVisual)}</td>
      <td>${renderRouteTreeCell({
        level,
        hasChildren: false,
        isLast: treeOptions.isLast !== false,
        continuationLevels: treeOptions.continuationLevels || [],
        visual: stepTypeVisual,
        content: stepContent,
        className: "is-route-step is-planning-order-step",
      })}</td>
      <td>
        <span class="speki-static-cell planning-order-quantity">
          <strong>${Number(stepQuantity || 0).toLocaleString("ru-RU")}</strong>
          <small>шт.</small>
        </span>
      </td>
      <td>${renderPlanningDemoLaborField(stepDemoLaborKey, stepDemoLaborPlaceholder)}</td>
      <td>
        <div class="planning-order-state-cell">
          <span class="planning-v2-state-token is-${escapeAttribute(tone)}">${escapeHtml(tone === "warning" ? "проверьте" : isSmtStep ? "SMT" : isManufacturingOutputReceiptRouteStep(step) ? "приемка" : "готово")}</span>
          <button class="icon-button" data-planning-work-item="${escapeAttribute(itemId)}" type="button" title="Открыть операцию">${icon("chevronRight")}</button>
        </div>
      </td>
    </tr>
  `;
}

function renderPlanningWorkbenchV2Phase({ id, selectedItem, number, title, meta, status, tone = "neutral" }) {
  return `
    <button class="planning-v2-phase is-${escapeAttribute(tone)} ${id === selectedItem ? "is-active" : ""}" data-planning-work-item="${escapeAttribute(id)}" type="button">
      ${number ? `<b>${escapeHtml(number)}</b>` : ""}
      <span>
        <strong>${escapeHtml(title)}</strong>
        ${meta ? `<small>${escapeHtml(meta)}</small>` : ""}
      </span>
      <em>${escapeHtml(status || "")}</em>
    </button>
  `;
}

function renderPlanningWorkbenchV2TaskLane(route, task, routeSteps, selectedItem, planningQuantity) {
  const stats = getPlanningTaskOperationStats(route, task, routeSteps);
  const taskQuantity = normalizeQuantity(task.quantity || 1);
  const orderQuantity = normalizeQuantity(planningQuantity * taskQuantity);
  const taskUnit = /маршрут/i.test(task.unit || "") ? "шт." : task.unit || "шт.";

  return `
    <article class="planning-v2-lane ${task.isMain ? "is-main" : ""}">
      <button class="planning-v2-lane-head ${getPlanningWorkItemId("task", task.id) === selectedItem ? "is-active" : ""}" data-planning-work-item="${escapeAttribute(getPlanningWorkItemId("task", task.id))}" type="button">
        <span>
          <strong>${escapeHtml(task.title || "Составная часть")}</strong>
        </span>
        <b>${orderQuantity.toLocaleString("ru-RU")} ${escapeHtml(taskUnit)}</b>
      </button>

      ${stats.steps.length ? `
        <div class="planning-v2-step-row">
          ${stats.steps.map((step) => renderPlanningWorkbenchV2StepPill(step, selectedItem)).join("")}
        </div>
      ` : `
        <div class="planning-v2-lane-empty">операции для этой части не заданы</div>
      `}
    </article>
  `;
}

function renderPlanningWorkbenchV2StepPill(step, selectedItem) {
  const itemId = getPlanningWorkItemId("step", step.id);
  const tone = getPlanningStepTone(step);
  const isSmtStep = routeStepRequiresManualPlanningLine(step, planningState) || isSmtOperationWorkCenter(step.workCenterId, step, planningState);
  return `
    <button class="planning-v2-step-pill is-${escapeAttribute(tone)} ${itemId === selectedItem ? "is-active" : ""}" data-planning-work-item="${escapeAttribute(itemId)}" type="button">
      <b>${Number(step.stepOrder || 0)}</b>
      <span>
        <strong>${escapeHtml(step.operationName || "Операция")}</strong>
        <small>${escapeHtml(getPlanningStepLineLabel(step))}</small>
      </span>
      ${isSmtStep ? `<em>SMT</em>` : isManufacturingOutputReceiptRouteStep(step) ? `<em>приемка</em>` : ""}
    </button>
  `;
}

function renderPlanningWorkbenchV2Detail(route, transferSummary, tasks, routeSteps, selectedItem) {
  const { type, id } = parsePlanningWorkItemId(selectedItem);
  if (type === "supply") return renderPlanningWorkbenchV2SupplyDetail(route, transferSummary, tasks, routeSteps);
  if (type === "chain") return renderPlanningWorkbenchV2ChainDetail(route, transferSummary, tasks, routeSteps);
  if (type === "shifts") return renderPlanningWorkbenchV2ShiftOrdersDetail(route, transferSummary, routeSteps);
  if (type === "schedule" || type === "batches") return renderPlanningWorkbenchV2ScheduleDetail(route, transferSummary);
  if (type === "task") {
    const task = tasks.find((item) => item.id === id) || tasks.find((item) => item.isMain) || tasks[0];
    return renderPlanningWorkbenchV2TaskDetail(route, task, transferSummary, routeSteps);
  }
  if (type === "step") {
    const step = routeSteps.find((item) => item.id === id);
    if (step) return renderPlanningWorkbenchV2StepDetail(route, step, transferSummary, routeSteps);
  }
  return renderPlanningWorkbenchV2SupplyDetail(route, transferSummary, tasks, routeSteps);
}

function renderPlanningWorkbenchV2Record({ eyebrow, title, subtitle, status = "", tone = "neutral", body = "" }) {
  return `
    <section class="module-panel planning-v2-record is-${escapeAttribute(tone)}">
      <header class="planning-v2-record-head">
        <div>
          ${eyebrow ? `<span class="eyebrow">${escapeHtml(eyebrow)}</span>` : ""}
          <h3>${escapeHtml(title || "Этап")}</h3>
          ${subtitle ? `<p>${escapeHtml(subtitle)}</p>` : ""}
        </div>
        ${status ? `<em class="planning-v2-record-status">${escapeHtml(status)}</em>` : ""}
      </header>

      ${body}
    </section>
  `;
}

function renderPlanningWorkbenchV2Section(title, subtitle, content, options = {}) {
  return `
    <section class="planning-v2-record-section ${options.className ? escapeAttribute(options.className) : ""}">
      <header>
        <div>
          <strong>${escapeHtml(title || "")}</strong>
          ${subtitle ? `<span>${escapeHtml(subtitle)}</span>` : ""}
        </div>
        ${options.badge ? `<em>${escapeHtml(options.badge)}</em>` : ""}
      </header>
      ${content}
    </section>
  `;
}

